[ExtensionOf(classstr(CustAccountStatementIntContract))]
final class ETG_CustAccountStatementIntContract_Extension
{
    public boolean              financialDimensions;
    public DimensionSetName     financialDimSet;
}

Method.Source:
[
    DataMemberAttribute('FinancialDimensions'),
    SysOperationLabelAttribute(literalStr("Financial Dimensions")),
    SysOperationGroupMemberAttribute('Criteria'),
    SysOperationDisplayOrderAttribute('13')
]
public boolean parmFinancialDimensions(boolean _financialDimensions = financialDimensions)
{
    financialDimensions = _financialDimensions;
    return financialDimensions;
}

[
    DataMemberAttribute('DimensionSetName'),
    SysOperationGroupMemberAttribute('FinDimSet'),
    SysOperationGroupMemberAttribute('Criteria'),
    SysOperationDisplayOrderAttribute('14')
]
public DimensionSetName parmFinancialDimSet(DimensionSetName _financialDimSet = financialDimSet)
{
    financialDimSet = _financialDimSet;
    return financialDimSet;
}

/// <summary>
/// Validates the dialog values for errors.
/// </summary>
/// <returns>
/// false if an error has occurred in the dialog values; otherwise true .
/// </returns>
/// <remarks>
/// The dialog values are handled through the contract.
/// </remarks>
public boolean validate()
{
    boolean valid = true;

    next validate();

    if (this.parmFinancialDimensions() && !this.parmFinancialDimSet())
    {
        valid = checkFailed("@ETG_ENG_Labels:SelectFinancialDimensionSet");
    }

    return valid;
}
